function crc32(str) {
  let crc = 0xFFFFFFFF;

  for (let i = 0; i < str.length; i++) {
    const byte = str.charCodeAt(i) & 0xff;
    crc ^= byte;
    for (let j = 7; j >= 0; j--) {
      crc = (crc >>> 1) ^ (-(crc & 1) & 0xEDB88320);
    }
  }

  return ~crc;
}

// 用法示例：
console.log(crc32("hello world!")); // 输出：222957957
```

